def minPath(grid, k):
    N = len(grid)
    directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
    visited = [[False] * N for _ in range(N)]
    min_path = []

    def dfs(x, y, path, path_len):
        if path_len == k:
            if not min_path or path < min_path:
                min_path = path[:]
            return

        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < N and 0 <= ny < N and not visited[nx][ny]:
                visited[nx][ny] = True
                path.append(grid[nx][ny])
                dfs(nx, ny, path, path_len + 1)
                path.pop()
                visited[nx][ny] = False

    for i in range(N):
        for j in range(N):
            visited[i][j] = True
            dfs(i, j, [grid[i][j]], 1)
            visited[i][j] = False

    return min_path

